INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1602, 195759, 1, 1948, '是我对不起', '人世间情为何物，让我甘愿为它而死，为它而生。经过你的好意劝说。我终于理解到在当今的世界上还有比爱情更重要更伟大的事务，那就是学习。学习虽然很苦，很累，但请你相信我会努力，我会开着“学习号”全速前进，我不会在误入歧途，想入非非。是你让我觉悟，是你让我懂得这个真理，是你让我不会因此而感到后悔。你没有必要向我说对不起，说对不起的人应该是我.是我。我不应该为了爱而耽误了你我的前途，我相信你的作法是对的，我支持你，同时我也会悔改，不会在执迷不悟了。相信我，我知道这一切都是为了即将到来的中考，一切都是为了你我未来的前途着想。我并非会为此而感到伤心，反而我会很高兴，因为在我的花样年华中我结识一位挚友.知己，她就是你。这不是一般人可以理解到其中的含义的。你改变了我，改变了我的未来。我会记住你，永远的记住你。愿我们携手共进！', '人世间情为何物，让我甘愿为它而死，为它而生。经过你的好意劝说。我终于理解到在当今的世界上还有比爱情更重要更伟大的事务，那就是学习。学习虽然很苦，很累，但请你相信我会努力，我会开着“学习号”全速前进，我不会在误入歧途，想入非非。是你让我觉悟，是你让我懂得这个真理，是你让我不会因此而感到后悔。你没有必要向我说对不起，说对不起的人应该是我.是我。我不应该为了爱而耽误了你我的前途，我相信你的作法是对的，我支持你，同时我也会悔改，不会在执迷不悟了。相信我，我知道这一切都是为了即将到来的中考，一切都是为了你我未来的前途着想。我并非会为此而感到伤心，反而我会很高兴，因为在我的花样年华中我结识一位挚友.知己，她就是你。这不是一般人可以理解到其中的含义的。你改变了我，改变了我的未来。我会记住你，永远的记住你。愿我们携手共进！', NULL, '2003-02-08 01:05:00', 14, '20030328213231_bbsid_195759_board_1_e1a57e9553.html', '20030328213231');
